import{_ as a,o as c,c as o,a3 as d}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module extract","description":"extract 模块负责符号提取的核心流程，主要职责包括加载与评估缓存状态、并行解析源文件 AST、构建模块依赖关系，以及持久化提取结果。模块内部通过匿名命名空间封装了多个辅助结构与函数（如 CacheEvaluation、ParallelASTResult、LoadedCaches 以及各类 load_*_async / save_*_async 函数），实现异步 I/O 与并发任务调度。模块向外界暴露的唯一公有接口是 extract_project_async，调用者传入项目标识符和事件循环即可启动异步提取操作，操作结果以整型错误码返回。整个实现依赖于 config 模块的配置与 support 模块的基础工具（如路径规范化、缓存键构建及文件读写）。","frontmatter":{"title":"Module extract","description":"extract 模块负责符号提取的核心流程，主要职责包括加载与评估缓存状态、并行解析源文件 AST、构建模块依赖关系，以及持久化提取结果。模块内部通过匿名命名空间封装了多个辅助结构与函数（如 CacheEvaluation、ParallelASTResult、LoadedCaches 以及各类 load_*_async / save_*_async 函数），实现异步 I/O 与并发任务调度。模块向外界暴露的唯一公有接口是 extract_project_async，调用者传入项目标识符和事件循环即可启动异步提取操作，操作结果以整型错误码返回。整个实现依赖于 config 模块的配置与 support 模块的基础工具（如路径规范化、缓存键构建及文件读写）。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/index.md","filePath":"zh/clore/modules/extract/index.md"}'),t={name:"zh/clore/modules/extract/index.md"};function r(l,e,i,s,n,h){return c(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="module-extract" tabindex="-1">Module <code>extract</code> <a class="header-anchor" href="#module-extract" aria-label="Permalink to &quot;Module `extract`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>extract</code> 模块负责符号提取的核心流程，主要职责包括加载与评估缓存状态、并行解析源文件 AST、构建模块依赖关系，以及持久化提取结果。模块内部通过匿名命名空间封装了多个辅助结构与函数（如 <code>CacheEvaluation</code>、<code>ParallelASTResult</code>、<code>LoadedCaches</code> 以及各类 <code>load_*_async</code> / <code>save_*_async</code> 函数），实现异步 I/O 与并发任务调度。模块向外界暴露的唯一公有接口是 <code>extract_project_async</code>，调用者传入项目标识符和事件循环即可启动异步提取操作，操作结果以整型错误码返回。整个实现依赖于 <code>config</code> 模块的配置与 <code>support</code> 模块的基础工具（如路径规范化、缓存键构建及文件读写）。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../agent/"><code>agent</code></a></li><li><a href="./../agent/tools"><code>agent:tools</code></a></li><li><a href="./../generate/"><code>generate</code></a></li><li><a href="./../generate/analysis"><code>generate:analysis</code></a></li><li><a href="./../generate/common"><code>generate:common</code></a></li><li><a href="./../generate/diagram"><code>generate:diagram</code></a></li><li><a href="./../generate/dryrun"><code>generate:dryrun</code></a></li><li><a href="./../generate/evidence"><code>generate:evidence</code></a></li><li><a href="./../generate/"><code>generate:evidence_builder</code></a></li><li><a href="./../generate/model"><code>generate:model</code></a></li><li><a href="./../generate/page"><code>generate:page</code></a></li><li><a href="./../generate/planner"><code>generate:planner</code></a></li><li><a href="./../generate/scheduler"><code>generate:scheduler</code></a></li><li><a href="./../generate/symbol"><code>generate:symbol</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-extracterror" tabindex="-1"><code>clore::extract::ExtractError</code> <a class="header-anchor" href="#clore-extract-extracterror" aria-label="Permalink to &quot;`clore::extract::ExtractError`&quot;">​</a></h3><p>Declaration: <code>extract/extract.cppm:21</code></p><p>Definition: <code>extract/extract.cppm:21</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该结构体仅包含一个 <code>std::string</code> 成员 <code>message</code>，用于存储错误描述信息。由于未定义任何用户提供的构造函数、赋值操作符或析构函数，<code>clore::extract::ExtractError</code> 是一个聚合类型，其构造、复制和销毁完全依赖 <code>std::string</code> 的相应操作。该设计使得错误消息的存储和传递具有自然的值语义，且不引入额外的资源管理复杂性。任何对 <code>message</code> 的修改都会直接改变错误对象的有效状态，因此保持 <code>message</code> 内容的完整性是该结构体的主要不变性。</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-extract-project-async" tabindex="-1"><code>clore::extract::extract_project_async</code> <a class="header-anchor" href="#clore-extract-extract-project-async" aria-label="Permalink to &quot;`clore::extract::extract_project_async`&quot;">​</a></h3><p>Declaration: <code>extract/extract.cppm:25</code></p><p>Definition: <code>extract/extract.cppm:539</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::extract_project_async</code> 的整体算法按阶段组织，异步控制流通过 <code>kota::event_loop</code> 驱动。首先加载编译数据库并过滤条目，标准化文件路径；接着从 <code>workspace_root</code> 启动 <code>load_caches_async</code> 获得 <code>extract_cache_records</code> 和 <code>clice_cache</code>。对于每个条目，利用 <code>compile_signature</code>、<code>source_hash</code> 及依赖变化检测（<code>cache::dependencies_changed</code>）计算出 <code>CacheEvaluation</code>，分别记录 <code>scan_valid</code> 和 <code>ast_valid</code> 状态，并填充 <code>seeded_scan_cache</code>。然后通过 <code>build_dependency_graph_async</code> 构建 <code>DependencyGraph</code>，随后执行拓扑排序 <code>topological_order</code> 得到文件处理顺序。并行 AST 提取由 <code>extract_ast_batch_async</code> 完成，它接收 <code>filtered_db.entries</code>、<code>prepared_entries</code>、<code>cache_evaluations</code> 和 <code>dep_graph</code>，返回包含每个条目 <code>ParallelASTResult</code> 或错误的结果向量。</p><p>在按序处理每个条目时，若 <code>cache_state_it-&gt;second.ast_valid</code> 为真且缓存记录存在，则直接从 <code>cache_record_it-&gt;second.ast</code> 获取 AST 视图，否则从并行结果中取 <code>ast_data</code> 并获取对应的 <code>ast_deps_snapshot</code>。对于每个符号，通过 <code>resolve_symbol_location_path</code> 解析声明和定义的文件路径（使用 <code>resolved_path_cache</code> 对同一路径的解析结果去重），应用 <code>filter_root</code> 过滤，再在 <code>model.symbols</code> 中插入或合并符号。关系处理包括继承、调用和引用，分别推入派生、调用和被调用列表。根据 <code>source_hash</code> 的有无决定是更新/插入 <code>cache_records</code> 还是移除该记录。所有条目处理完毕后，依次调用 <code>rebuild_model_indexes</code>、<code>build_module_info</code>、<code>rebuild_lookup_maps</code>，并通过 <code>kota::queue</code> 在后台线程异步解析源代码片段。最后通过 <code>save_caches_async</code> 将缓存写回磁盘。控制流中任何阶段遇到错误都会先尝试 <code>fail_after_persist</code> 以尽最大努力持久化缓存，再传播 <code>ExtractError</code>。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Loads compilation database from disk</li><li>Loads caches from disk (cache records and clice cache)</li><li>Persists caches to disk after extraction or on failure</li><li>Logs progress and statistics via <code>logging::info</code> and <code>logging::cache_hit_rate</code></li><li>Mutates <code>ProjectModel</code> object by adding symbols, files, namespaces, and relations</li><li>Rebuilds model indexes and lookup maps</li><li>Resolves source snippets for symbols</li><li>Updates in-memory cache records map and clice cache</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>config</code> parameter: <code>compile_commands_path</code>, <code>filter</code>, <code>workspace_root</code></li><li>Compilation database entries (file paths, directories, compile commands)</li><li>Cache records map (previously persisted AST and scan results)</li><li>Clice cache (PCH and PCM entries)</li><li>Event loop <code>loop</code> for async operations</li><li>Scan cache (seeded from disk)</li><li>Filter root from <code>config.filter</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Cache records map (updated or inserted AST and scan data)</li><li>Clice cache (possibly unchanged, but passed to persistence)</li><li><code>ProjectModel</code> object: <code>symbols</code>, <code>files</code>, <code>namespaces</code>, <code>file_order</code>, <code>modules</code></li><li>Resolved path cache (internal map for repeated path resolutions)</li><li>Log output via <code>logging</code> functions</li><li>Disk via <code>save_caches_async</code> (persisting caches)</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called as the main entry point for extracting a project&#39;s symbols asynchronously</li><li>Uses coroutine pattern with <code>kota::task</code> and <code>co_await</code></li><li>Cooperates with caching subsystem to avoid redundant AST extraction</li><li>Relies on parallel AST extraction batch task for performance</li><li>Handles errors via <code>kota::fail</code> and custom error type <code>ExtractError</code></li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>extract 模块是符号提取的核心实现，对外仅暴露 <code>extract_project_async</code> 这一异步入口点。它向上承接调用者传入的项目标识符和事件循环，向下依赖 <code>config</code>（应用配置）、<code>std</code>（标准库）以及 <code>support</code>（基础工具与日志）三个模块。模块内部完全使用匿名命名空间封装细节，所有辅助函数、状态结构体和类型别名均不对外可见，实现了严格的接口隔离。</p><p>在内部，extract 被组织为三层异步流水线：底层是缓存 I/O 层，以模板函数 <code>run_cache_io_async</code> 和 <code>run_worker_task_async</code> 为基础，统一封装了对 <code>clice_cache</code> 和 <code>extract_cache_records</code> 的加载与持久化（体现在 <code>load_caches_async</code>、<code>save_caches_async</code> 等函数中）。中间层是 AST 提取层，由 <code>extract_ast_batch_async</code> 协调批量任务，每个条目通过 <code>extract_ast_entry</code> 生成 <code>ParallelASTResult</code>（包含 AST 数据、依赖关系及符号信息）。上层为模块构建层，<code>build_module_info</code> 利用扫描缓存内的 <code>GroupedModuleInfo</code>（含接口标志、模块名、导入列表）填充项目模型中的模块信息。整个流程以 <code>CacheEvaluation</code>（编译签名、源哈希、AST/扫描有效性）和 <code>PreparedEntryState</code>（归一化文件路径、缓存键）作为状态跟踪单元，结合 <code>LoadedCaches</code> 与 <code>cache_records</code> 实现增量复用，最终通过 <code>extract_project_async</code> 返回操作结果。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../support/">Module support</a></li></ul>',33)])])}const _=a(t,[["render",r]]);export{u as __pageData,_ as default};
